// Auto-migrated from the original static guide HTML. Structural markup
// and code samples are preserved; inline styles, scripts, and the guide's
// own bespoke syntax-highlight token classes were stripped so every guide
// renders through the one shared GuideReader stylesheet.
export const html: string = "<section class=\"step\" id=\"s1\">\n<div class=\"step-header\">\n<div class=\"step-badge\">01</div>\n<h2>How Django serves HTML</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Before touching syntax, understand the request/response cycle. This is the single biggest mental shift coming from static HTML files.</div>\n<div class=\"step-body\">\n<p>In vanilla frontend work, a browser requests <strong>index.html</strong> and the server returns that exact file, byte for byte. In Django, there is no static file being returned. A <strong>view function</strong> runs Python code, builds a <strong>template</strong> by filling placeholders with real data, and sends the resulting HTML string back as the response.</p>\n<p>The flow for every page request is:</p>\n<ol>\n<li><strong>urls.py</strong> matches the requested path to a view</li>\n<li>The <strong>view</strong> (a Python function or class) runs, fetches data, builds a <strong>context</strong> dictionary</li>\n<li>The view calls <code>render()</code>, which loads a <strong>.html</strong> template and merges it with the context</li>\n<li>Django's <strong>template engine</strong> replaces <code>{{ }}</code> and <code>{% %}</code> with real values and HTML</li>\n<li>The final, plain HTML string goes to the browser. The browser never sees Django syntax</li>\n</ol>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">blog/views.py</span>\n</div>\n<pre><span>from</span> django.shortcuts <span>import</span> render\n<span>from</span> .models <span>import</span> Post\n\n<span>def</span> <span>post_list</span>(request):\n posts = Post.objects.<span>all</span>()\n context = {<span>\"posts\"</span>: posts, <span>\"page_title\"</span>: <span>\"Blog\"</span>}\n <span>return</span> <span>render</span>(request, <span>\"blog/post_list.html\"</span>, context)</pre>\n</div>\n<div>Think of <code>context</code> as the bridge between Python and HTML. Anything you want to use in the template must be a key in this dictionary. There is no other way for the template to see your Python variables.</div>\n</section>\n<section class=\"step\" id=\"s2\">\n<div class=\"step-header\">\n<div class=\"step-badge\">02</div>\n<h2>Template Language basics</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django Template Language (DTL) has exactly two syntaxes. Once these click, every tag in this guide is just a variation on them.</div>\n<div class=\"step-body\">\n<p>There are only two things to memorize:</p>\n<ul>\n<li><code>{{ variable }}</code> outputs a value, like writing text with JavaScript template literals</li>\n<li><code>{% tag %}</code> performs logic: loops, conditionals, includes, URL building. It outputs nothing by itself</li>\n</ul>\n<p>DTL is intentionally limited. You <strong>cannot</strong> call functions with arguments, do arithmetic with operators like <code>+</code> directly on output, or write arbitrary Python. This is by design: it keeps designers and template authors from accidentally writing business logic in HTML. All real logic belongs in the view or in a custom filter.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/example.html</span>\n</div>\n<pre>&lt;h1&gt;{{ page_title }}&lt;/h1&gt;\n\n{<span>% if</span> posts <span>%}</span>\n &lt;p&gt;There are {{ posts<span>|length</span> }} posts.&lt;/p&gt;\n{<span>% else %</span>}\n &lt;p&gt;No posts yet.&lt;/p&gt;\n{<span>% endif %</span>}</pre>\n</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> writing <code>{{ user.is_authenticated() }}</code> with parentheses. DTL never calls methods with <code>()</code> -- it auto-detects callables and calls them for you. Just write <code>{{ user.is_authenticated }}</code>.</div>\n</section>\n<section class=\"step\" id=\"s3\">\n<div class=\"step-header\">\n<div class=\"step-badge\">03</div>\n<h2>Variables and filters</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Filters are Django's version of helper functions and replace the small formatting snippets you would normally write in JavaScript.</div>\n<div class=\"step-body\">\n<p>Dot notation in templates does triple duty. <code>{{ post.title }}</code> tries, in order: dictionary lookup (<code>post[\"title\"]</code>), then attribute lookup (<code>post.title</code>), then list index lookup (<code>post[0]</code>). You never need to know which one applies, Django figures it out.</p>\n<p>Filters transform a value using a pipe, exactly like a Unix pipe. Chain as many as you want, left to right.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n</div>\n<pre>{{ post.title<span>|upper</span> }}\n{{ post.body<span>|truncatewords</span>:<span>30</span> }}\n{{ post.created<span>|date</span>:<span>\"F j, Y\"</span> }}\n{{ post.price<span>|floatformat</span>:<span>2</span> }}\n{{ user.bio<span>|default</span>:<span>\"No bio yet.\"</span> }}\n{{ post.body<span>|linebreaks</span> }}\n{{ request.GET.q<span>|default_if_none</span>:<span>\"\"</span> }}\n{{ value<span>|lower|slugify</span> }} <span>{# chained filters #}</span></pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> <code>|safe</code> tells Django this string is trusted and should not be HTML-escaped. Only use it on content you control, never on raw user input, or you open an XSS hole.</div>\n<div>By default Django auto-escapes every variable: <code>&lt;</code>, <code>&gt;</code>, <code>&amp;</code>, quotes are all converted to entities automatically. This is why pasting raw HTML strings into <code>{{ }}</code> just shows the tags as text instead of rendering them, that protection is intentional.</div>\n</section>\n<section class=\"step\" id=\"s4\">\n<div class=\"step-header\">\n<div class=\"step-badge\">04</div>\n<h2>{% if %} and {% for %}</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>These two tags replace nearly every <code>.map()</code> and ternary you would write in JSX or a JS templating library.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n</div>\n<pre>{<span>% for</span> post <span>in</span> posts <span>%}</span>\n &lt;article class=<span>\"card\"</span>&gt;\n &lt;h2&gt;{{ post.title }}&lt;/h2&gt;\n &lt;span class=<span>\"badge\"</span>&gt;{{ forloop.counter }} of {{ posts<span>|length</span> }}&lt;/span&gt;\n &lt;/article&gt;\n{<span>% empty %</span>}\n &lt;p&gt;No posts to show.&lt;/p&gt;\n{<span>% endfor %</span>}\n\n{<span>% if</span> post.is_published <span>and</span> request.user.is_staff <span>%}</span>\n &lt;span class=<span>\"tag tag-live\"</span>&gt;Live&lt;/span&gt;\n{<span>% elif</span> <span>not</span> post.is_published <span>%}</span>\n &lt;span class=<span>\"tag tag-draft\"</span>&gt;Draft&lt;/span&gt;\n{<span>% endif %</span>}</pre>\n</div>\n<div><code>{% empty %}</code> is the Django-native way to render a fallback when a loop has zero items, instead of writing a separate <code>{% if posts %}</code> check around it.</div>\n<div class=\"step-body\">\n<p>Inside a <code>{% for %}</code> loop, Django exposes a <code>forloop</code> object with useful state:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n</div>\n<pre>{{ forloop.counter }} <span>&lt;!-- 1-indexed position --&gt;</span>\n{{ forloop.counter0 }} <span>&lt;!-- 0-indexed position --&gt;</span>\n{{ forloop.first }} <span>&lt;!-- True on first iteration --&gt;</span>\n{{ forloop.last }} <span>&lt;!-- True on last iteration --&gt;</span>\n{{ forloop.revcounter }} <span>&lt;!-- counts down to 1 --&gt;</span></pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> use <code>{% if forloop.last %}{% else %},{% endif %}</code> inside a loop to join items with commas without trailing punctuation, a common list-rendering need.</div>\n</section>\n<section class=\"step\" id=\"s5\">\n<div class=\"step-header\">\n<div class=\"step-badge\">05</div>\n<h2>Template inheritance</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>This replaces copy-pasting your <code>&lt;head&gt;</code>, nav, and footer into every HTML file. It is the single most impactful habit to adopt early.</div>\n<div class=\"step-body\">\n<p>One <strong>base.html</strong> defines the page skeleton with named <code>{% block %}</code> regions. Every other template <code>{% extends %}</code> it and overrides only the blocks it needs to change.</p>\n</div>\n<div>\n<div class=\"compare-col\">\n<div class=\"compare-head\">Vanilla habit</div>\n<pre>about.html, contact.html, and\nindex.html each contain a full\ncopy of &lt;head&gt;, the nav bar,\nand the footer. Updating the\nnav means editing every file.</pre>\n</div>\n<div class=\"compare-col\">\n<div class=\"compare-head\">Django way</div>\n<pre>base.html owns the shell once.\nabout.html, contact.html only\ncontain the content that's\nactually unique to that page.\nUpdate the nav in one place.</pre>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/base.html</span>\n</div>\n<pre>&lt;!DOCTYPE html&gt;\n&lt;html lang=<span>\"en\"</span>&gt;\n&lt;head&gt;\n &lt;meta charset=<span>\"UTF-8\"</span>&gt;\n &lt;title&gt;{<span>% block</span> title <span>%}</span>My Site{<span>% endblock %</span>}&lt;/title&gt;\n {<span>% load</span> static <span>%}</span>\n &lt;link rel=<span>\"stylesheet\"</span> href=<span>\"{% static 'css/base.css' %}\"</span>&gt;\n {<span>% block</span> extra_css <span>%}{% endblock %</span>}\n&lt;/head&gt;\n&lt;body&gt;\n {<span>% include</span> <span>\"partials/navbar.html\"</span> <span>%}</span>\n\n &lt;main&gt;\n {<span>% block</span> content <span>%}{% endblock %</span>}\n &lt;/main&gt;\n\n {<span>% include</span> <span>\"partials/footer.html\"</span> <span>%}</span>\n {<span>% block</span> extra_js <span>%}{% endblock %</span>}\n&lt;/body&gt;\n&lt;/html&gt;</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/blog/post_list.html</span>\n</div>\n<pre>{<span>% extends</span> <span>\"base.html\"</span> <span>%}</span>\n{<span>% load</span> static <span>%}</span>\n\n{<span>% block</span> title <span>%}</span>Blog -- My Site{<span>% endblock %</span>}\n\n{<span>% block</span> extra_css <span>%}</span>\n &lt;link rel=<span>\"stylesheet\"</span> href=<span>\"{% static 'css/blog.css' %}\"</span>&gt;\n{<span>% endblock %</span>}\n\n{<span>% block</span> content <span>%}</span>\n &lt;h1&gt;Latest Posts&lt;/h1&gt;\n {<span>% for</span> post <span>in</span> posts <span>%}</span>\n &lt;article&gt;{{ post.title }}&lt;/article&gt;\n {<span>% endfor %</span>}\n{<span>% endblock %</span>}</pre>\n</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> putting content outside any <code>{% block %}</code> in a child template. Anything outside a block is silently discarded, only what is inside a matching block name actually renders.</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> a child template can call <code>{{ block.super }}</code> inside an overridden block to keep the parent's content and add to it, instead of fully replacing it.</div>\n</section>\n<section class=\"step\" id=\"s6\">\n<div class=\"step-header\">\n<div class=\"step-badge\">06</div>\n<h2>include and reusable partials</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong><code>{% include %}</code> is Django's answer to a reusable component, the same instinct that leads to React components or Vue partials.</div>\n<div class=\"step-body\">\n<p>Use <code>{% include %}</code> for chunks of markup repeated across pages: a card, a nav, an alert box. Pass it extra variables with <code>with</code> so the same partial can render slightly differently each time.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/partials/card.html</span>\n</div>\n<pre>&lt;div class=<span>\"card\"</span>&gt;\n &lt;h3&gt;{{ title }}&lt;/h3&gt;\n &lt;p&gt;{{ description }}&lt;/p&gt;\n {<span>% if</span> highlight <span>%}</span>\n &lt;span class=<span>\"badge\"</span>&gt;Featured&lt;/span&gt;\n {<span>% endif %</span>}\n&lt;/div&gt;</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">used inside another template</span>\n</div>\n<pre>{<span>% include</span> <span>\"partials/card.html\"</span> <span>with</span> title=post.title description=post.summary highlight=<span>True</span> <span>%}</span></pre>\n</div>\n<div>Variables passed with <code>with</code> are only visible inside the included template, they do not leak back out. Add <code>only</code> after the variable list (<code>{% include \"x.html\" with a=1 only %}</code>) to stop the partial from also seeing the parent's full context, useful for truly isolated, drop-in components.</div>\n</section>\n<section class=\"step\" id=\"s7\">\n<div class=\"step-header\">\n<div class=\"step-badge\">07</div>\n<h2>url and static tags</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>These two tags are why you should never hardcode a path in a Django template. Hardcoded URLs and asset paths break the moment your project structure or domain changes.</div>\n<div class=\"step-body\">\n<p><strong>{% url %}</strong> reverses a named URL pattern into the actual path, so renaming a route in urls.py never breaks a link in a template. <strong>{% static %}</strong> resolves a static asset to its correct served URL, including a cache-busting hash in production if you use a manifest storage backend.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">blog/urls.py</span>\n</div>\n<pre>urlpatterns = [\n <span>path</span>(<span>\"posts/\"</span>, views.post_list, name=<span>\"post_list\"</span>),\n <span>path</span>(<span>\"posts/&lt;slug:slug&gt;/\"</span>, views.post_detail, name=<span>\"post_detail\"</span>),\n]</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n</div>\n<pre>{<span>% load</span> static <span>%}</span>\n\n&lt;a href=<span>\"{% url 'post_list' %}\"</span>&gt;All Posts&lt;/a&gt;\n&lt;a href=<span>\"{% url 'post_detail' slug=post.slug %}\"</span>&gt;{{ post.title }}&lt;/a&gt;\n\n&lt;img src=<span>\"{% static 'images/logo.svg' %}\"</span> alt=<span>\"Logo\"</span>&gt;\n&lt;link rel=<span>\"stylesheet\"</span> href=<span>\"{% static 'css/base.css' %}\"</span>&gt;\n&lt;script src=<span>\"{% static 'js/main.js' %}\"</span> defer&gt;&lt;/script&gt;</pre>\n</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> forgetting <code>{% load static %}</code> at the top of any template that uses <code>{% static %}</code>. It is not a global tag, it must be loaded per-template.</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> if a URL pattern belongs to an app with a namespace (<code>app_name = \"blog\"</code> in urls.py), reference it as <code>{% url 'blog:post_detail' slug=post.slug %}</code>.</div>\n</section>\n<section class=\"step\" id=\"s8\">\n<div class=\"step-header\">\n<div class=\"step-badge\">08</div>\n<h2>Custom tags and filters</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>When a built-in filter cannot do what you need, you write your own instead of cramming logic into the template with workarounds.</div>\n<div class=\"step-body\">\n<p>Custom filters and tags live in <code>app_name/templatetags/your_file.py</code>. That folder needs an empty <code>__init__.py</code> to be recognized as a package.</p>\n</div>\n<div class=\"tree\">\n<span>blog/</span>\n \u251c\u2500\u2500 <span>templatetags/</span>\n \u2502 \u251c\u2500\u2500 <span>__init__.py</span>\n \u2502 \u2514\u2500\u2500 <span>blog_extras.py</span> <span># your custom tags/filters live here</span>\n \u2514\u2500\u2500 <span>templates/</span></div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">blog/templatetags/blog_extras.py</span>\n</div>\n<pre><span>from</span> django <span>import</span> template\n\nregister = template.Library()\n\n<span>@register.filter</span>\n<span>def</span> <span>reading_time</span>(value):\n words = <span>len</span>(value.<span>split</span>())\n minutes = <span>max</span>(<span>1</span>, words // <span>200</span>)\n <span>return</span> <span>f</span><span>\"{minutes} min read\"</span>\n\n<span>@register.simple_tag</span>\n<span>def</span> <span>site_url</span>(path=<span>\"\"</span>):\n <span>return</span> <span>f</span><span>\"https://example.com/{path}\"</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n</div>\n<pre>{<span>% load</span> blog_extras <span>%}</span>\n\n&lt;span&gt;{{ post.body<span>|reading_time</span> }}&lt;/span&gt;\n&lt;a href=<span>\"{% site_url 'pricing' %}\"</span>&gt;Pricing&lt;/a&gt;</pre>\n</div>\n<div>Use a <strong>filter</strong> when you are transforming one value (<code>value|something</code>). Use a <strong>simple_tag</strong> when you need multiple arguments or no input value at all. After adding a new templatetags file, restart the dev server, Django only scans this on startup.</div>\n</section>\n<section class=\"step\" id=\"s9\">\n<div class=\"step-header\">\n<div class=\"step-badge\">09</div>\n<h2>Static files setup</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django does not serve a flat <code>/css</code> or <code>/js</code> folder like a vanilla site. Static assets go through a dedicated app-scoped system that needs a one-time setup.</div>\n<div class=\"step-body\">\n<p>Every app can have its own <code>static/</code> folder. Django collects all of them together. Mirror your app's name inside <code>static/</code> to avoid collisions between apps that both have a <code>style.css</code>.</p>\n</div>\n<div class=\"tree\">\n<span>blog/</span>\n \u251c\u2500\u2500 <span>static/</span>\n \u2502 \u2514\u2500\u2500 <span>blog/</span> <span># namespaced to avoid clashes</span>\n \u2502 \u251c\u2500\u2500 <span>css/</span>\n \u2502 \u2502 \u2514\u2500\u2500 <span>blog.css</span>\n \u2502 \u251c\u2500\u2500 <span>js/</span>\n \u2502 \u2502 \u2514\u2500\u2500 <span>blog.js</span>\n \u2502 \u2514\u2500\u2500 <span>images/</span>\n \u2514\u2500\u2500 <span>templates/</span></div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings.py</span>\n</div>\n<pre>STATIC_URL = <span>\"static/\"</span>\nSTATICFILES_DIRS = [BASE_DIR / <span>\"static\"</span>] <span># project-wide static, optional</span>\nSTATIC_ROOT = BASE_DIR / <span>\"staticfiles\"</span> <span># where collectstatic dumps files for prod</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n</div>\n<pre>{<span>% load</span> static <span>%}</span>\n&lt;link rel=<span>\"stylesheet\"</span> href=<span>\"{% static 'blog/css/blog.css' %}\"</span>&gt;\n&lt;script src=<span>\"{% static 'blog/js/blog.js' %}\"</span> defer&gt;&lt;/script&gt;</pre>\n</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> editing files inside <code>staticfiles/</code> directly. That folder is generated output from <code>collectstatic</code> and gets wiped and rebuilt. Always edit source files inside each app's <code>static/</code> folder.</div>\n<div>In development (<code>DEBUG = True</code>), Django serves static files automatically. In production, <code>DEBUG = False</code> and you need <code>collectstatic</code> plus Nginx, Whitenoise, or a CDN to actually serve them, Django itself stops serving static assets outside debug mode.</div>\n</section>\n<section class=\"step\" id=\"s10\">\n<div class=\"step-header\">\n<div class=\"step-badge\">10</div>\n<h2>CSS architecture in Django</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Plain CSS works exactly the same in Django as it does anywhere, the only real difference is where files live and how they get linked. Knowing the conventions avoids fighting the framework.</div>\n<div class=\"step-body\">\n<p>Your CSS itself does not change at all. What changes is organization. A common, scalable layout for a multi-app project:</p>\n</div>\n<div class=\"tree\">\n<span>static/</span> <span># project-wide, shared across all apps</span>\n \u251c\u2500\u2500 <span>css/</span>\n \u2502 \u251c\u2500\u2500 <span>base.css</span> <span># reset, variables, typography</span>\n \u2502 \u251c\u2500\u2500 <span>layout.css</span> <span># nav, footer, grid shell</span>\n \u2502 \u2514\u2500\u2500 <span>components.css</span> <span># buttons, cards, forms, badges</span>\n \u2514\u2500\u2500 <span>js/</span>\n \u2514\u2500\u2500 <span>main.js</span>\n<span>blog/static/blog/css/</span> <span># app-specific overrides</span>\n \u2514\u2500\u2500 <span>blog.css</span></div>\n<div class=\"step-body\">\n<p>Load shared CSS once in <strong>base.html</strong>, and let each page add its own extra CSS through the <code>extra_css</code> block pattern shown earlier in Step 5. This keeps page-specific styles out of the global bundle.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">CSS</span>\n<span class=\"code-file\">static/css/base.css</span>\n</div>\n<pre><span>:root</span> {\n <span>--color-primary</span>: <span>#2563eb</span>;\n <span>--color-text</span>: <span>#1f2937</span>;\n <span>--radius</span>: <span>8px</span>;\n}\n<span>*</span> { <span>box-sizing</span>: border-box; }\n<span>body</span> { <span>font-family</span>: system-ui, sans-serif; <span>color</span>: <span>var</span>(<span>--color-text</span>); }</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> CSS variables (custom properties) work great alongside Django. Define your design tokens once in <code>:root</code> inside <code>base.css</code> and every app's CSS can reference the same palette without a build step.</div>\n</section>\n<section class=\"step\" id=\"s11\">\n<div class=\"step-header\">\n<div class=\"step-badge\">11</div>\n<h2>Images and media uploads</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Static files and media files are two different systems in Django. Mixing them up is one of the most common early bugs.</div>\n<div class=\"step-body\">\n<p><strong>Static files</strong> are assets that ship with your code: logos, icons, your CSS and JS. <strong>Media files</strong> are content uploaded by users at runtime: profile pictures, blog post thumbnails. They use entirely separate settings and separate template logic.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings.py</span>\n</div>\n<pre>MEDIA_URL = <span>\"media/\"</span>\nMEDIA_ROOT = BASE_DIR / <span>\"media\"</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/urls.py</span>\n</div>\n<pre><span>from</span> django.conf <span>import</span> settings\n<span>from</span> django.conf.urls.static <span>import</span> static\n\nurlpatterns = [\n <span># ... your patterns ...</span>\n]\n\n<span>if</span> settings.DEBUG:\n urlpatterns += <span>static</span>(settings.MEDIA_URL, document_root=settings.MEDIA_ROOT)</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n</div>\n<pre><span>&lt;!-- static asset: no .url needed, just the path --&gt;</span>\n&lt;img src=<span>\"{% static 'blog/images/logo.svg' %}\"</span> alt=<span>\"Logo\"</span>&gt;\n\n<span>&lt;!-- uploaded media: comes from a model field, use .url --&gt;</span>\n{<span>% if</span> post.thumbnail <span>%}</span>\n &lt;img src=<span>\"{{ post.thumbnail.url }}\"</span> alt=<span>\"{{ post.title }}\"</span>&gt;\n{<span>% endif %</span>}</pre>\n</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> wrapping an <code>ImageField</code> with <code>{% static %}</code>. That tag is only for files inside your project's <code>static/</code> folders. Uploaded files use <code>.url</code> directly, never <code>{% static %}</code>.</div>\n</section>\n<section class=\"step\" id=\"s12\">\n<div class=\"step-header\">\n<div class=\"step-badge\">12</div>\n<h2>Tailwind and build tools</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django has no opinion on your CSS framework. Tailwind, Bootstrap, or plain CSS all integrate the same basic way, but Tailwind's build step needs one extra piece of plumbing.</div>\n<div class=\"step-body\">\n<p>Two common setups for Tailwind with Django:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">Option A: django-tailwind package</span>\n</div>\n<pre>pip install django-tailwind\npython manage.py tailwind init\npython manage.py tailwind install\npython manage.py tailwind start <span># watches and rebuilds on save</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Terminal</span>\n<span class=\"code-file\">Option B: standalone Tailwind CLI</span>\n</div>\n<pre>npx tailwindcss -i ./static_src/input.css -o ./static/css/output.css --watch</pre>\n</div>\n<div class=\"step-body\">\n<p>Either way, point <code>content</code> in your Tailwind config at every folder containing templates, so Tailwind can find the class names you actually use:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">JavaScript</span>\n<span class=\"code-file\">tailwind.config.js</span>\n</div>\n<pre><span>module</span>.exports = {\n content: [\n <span>\"./templates/**/*.html\"</span>,\n <span>\"./*/templates/**/*.html\"</span>, <span>// catches every app's templates folder</span>\n ],\n theme: { extend: {} },\n}</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> run the Tailwind watcher in one terminal and <code>runserver</code> in another during development. They are two separate processes, the build tool never replaces Django's dev server.</div>\n</section>\n<section class=\"step\" id=\"s13\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">13</div>\n<h2>Forms 101 and CSRF</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Every single POST form in Django needs CSRF protection or the request is rejected outright. This single tag trips up nearly every developer coming from vanilla HTML on their first form.</div>\n<div class=\"step-body\">\n<p>Django ships with Cross-Site Request Forgery protection enabled by default. Any <code>&lt;form method=\"post\"&gt;</code> must include <code>{% csrf_token %}</code> inside it, or the submission fails with a 403 Forbidden error.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n</div>\n<pre>&lt;form method=<span>\"post\"</span> action=<span>\"{% url 'contact' %}\"</span>&gt;\n {<span>% csrf_token %</span>}\n &lt;label for=<span>\"name\"</span>&gt;Name&lt;/label&gt;\n &lt;input type=<span>\"text\"</span> id=<span>\"name\"</span> name=<span>\"name\"</span> required&gt;\n\n &lt;label for=<span>\"email\"</span>&gt;Email&lt;/label&gt;\n &lt;input type=<span>\"email\"</span> id=<span>\"email\"</span> name=<span>\"email\"</span> required&gt;\n\n &lt;button type=<span>\"submit\"</span>&gt;Send&lt;/button&gt;\n&lt;/form&gt;</pre>\n</div>\n<div><code>{% csrf_token %}</code> renders a hidden input with a one-time token. Django checks this token on every POST, PUT, PATCH, and DELETE request to confirm it actually came from your own site, not from a malicious page tricking the user's browser into submitting a form.</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> GET forms do not need <code>{% csrf_token %}</code> at all, since GET requests should never change server state. Adding it there is harmless but unnecessary, only POST-style forms require it.</div>\n</section>\n<section class=\"step\" id=\"s14\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">14</div>\n<h2>Django Forms vs raw HTML</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>You are not required to use Django's Form class, raw HTML inputs work fine. But Form classes save you from writing repetitive validation and re-render-with-errors logic by hand.</div>\n<div class=\"step-body\">\n<p>A Django <code>Form</code> is a Python class that describes fields, validates submitted data, and can render itself as HTML. It is optional. Both approaches below produce a working contact form, the difference is how much boilerplate you write yourself.</p>\n</div>\n<div>\n<div class=\"compare-col\">\n<div class=\"compare-head\">Raw HTML, manual everything</div>\n<pre>&lt;input name=\"email\" type=\"email\"&gt;\n\n# view.py\nemail = request.POST.get(\"email\")\nif \"@\" not in email:\n errors.append(\"Invalid email\")\n# ...repeat per field, every project</pre>\n</div>\n<div class=\"compare-col\">\n<div class=\"compare-head\">Django Form class</div>\n<pre>class ContactForm(forms.Form):\n email = forms.EmailField()\n\nform = ContactForm(request.POST)\nif form.is_valid():\n email = form.cleaned_data[\"email\"]\n# validation, errors, re-render: free</pre>\n</div>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">blog/forms.py</span>\n</div>\n<pre><span>from</span> django <span>import</span> forms\n\n<span>class</span> <span>ContactForm</span>(forms.Form):\n name = forms.<span>CharField</span>(max_length=<span>100</span>)\n email = forms.<span>EmailField</span>()\n message = forms.<span>CharField</span>(widget=forms.Textarea)</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">blog/views.py</span>\n</div>\n<pre><span>def</span> <span>contact</span>(request):\n <span>if</span> request.method == <span>\"POST\"</span>:\n form = <span>ContactForm</span>(request.POST)\n <span>if</span> form.<span>is_valid</span>():\n <span># form.cleaned_data is now safe, typed, validated data</span>\n <span>send_email</span>(form.cleaned_data)\n <span>return</span> <span>redirect</span>(<span>\"thank_you\"</span>)\n <span>else</span>:\n form = <span>ContactForm</span>()\n <span>return</span> <span>render</span>(request, <span>\"blog/contact.html\"</span>, {<span>\"form\"</span>: form})</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">blog/contact.html</span>\n</div>\n<pre>&lt;form method=<span>\"post\"</span>&gt;\n {<span>% csrf_token %</span>}\n {{ form.as_p }}\n &lt;button type=<span>\"submit\"</span>&gt;Send&lt;/button&gt;\n&lt;/form&gt;</pre>\n</div>\n<div>The same view handles both GET (show empty form) and POST (validate submitted data) by branching on <code>request.method</code>. This single-view pattern is the standard Django idiom, you rarely need separate routes for \"show form\" and \"handle form\".</div>\n</section>\n<section class=\"step\" id=\"s15\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">15</div>\n<h2>ModelForms</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>If a form maps directly to a database model, writing the fields twice (once in models.py, once in forms.py) is wasted effort. ModelForm generates the form from the model automatically.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">blog/models.py</span>\n</div>\n<pre><span>class</span> <span>Post</span>(models.Model):\n title = models.<span>CharField</span>(max_length=<span>200</span>)\n body = models.<span>TextField</span>()\n published = models.<span>BooleanField</span>(default=<span>False</span>)</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">blog/forms.py</span>\n</div>\n<pre><span>from</span> django <span>import</span> forms\n<span>from</span> .models <span>import</span> Post\n\n<span>class</span> <span>PostForm</span>(forms.ModelForm):\n <span>class</span> <span>Meta</span>:\n model = Post\n fields = [<span>\"title\"</span>, <span>\"body\"</span>, <span>\"published\"</span>]\n <span># or fields = \"__all__\" to include every model field</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">blog/views.py</span>\n</div>\n<pre><span>def</span> <span>create_post</span>(request):\n <span>if</span> request.method == <span>\"POST\"</span>:\n form = <span>PostForm</span>(request.POST)\n <span>if</span> form.<span>is_valid</span>():\n post = form.<span>save</span>() <span># writes directly to the database</span>\n <span>return</span> <span>redirect</span>(<span>\"post_detail\"</span>, slug=post.slug)\n <span>else</span>:\n form = <span>PostForm</span>()\n <span>return</span> <span>render</span>(request, <span>\"blog/post_form.html\"</span>, {<span>\"form\"</span>: form})\n\n<span>def</span> <span>edit_post</span>(request, pk):\n post = <span>get_object_or_404</span>(Post, pk=pk)\n form = <span>PostForm</span>(request.POST <span>or</span> <span>None</span>, instance=post)\n <span>if</span> form.<span>is_valid</span>():\n form.<span>save</span>()\n <span>return</span> <span>redirect</span>(<span>\"post_detail\"</span>, slug=post.slug)\n <span>return</span> <span>render</span>(request, <span>\"blog/post_form.html\"</span>, {<span>\"form\"</span>: form})</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> passing <code>instance=post</code> reuses the exact same form and template for both create and edit. The form pre-fills with existing values when an instance is given, and stays blank when it is not.</div>\n</section>\n<section class=\"step\" id=\"s16\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">16</div>\n<h2>Rendering fields by hand</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong><code>{{ form.as_p }}</code> is fast but gives you almost no control over markup or classes. Real production pages need custom layout and your own CSS classes on every input.</div>\n<div class=\"step-body\">\n<p>Loop over <code>form</code> directly, or reference each field by name, to get full control over the HTML structure while Django still handles values, errors, and widget attributes.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">Full manual control, field by field</span>\n</div>\n<pre>&lt;form method=<span>\"post\"</span> class=<span>\"form\"</span>&gt;\n {<span>% csrf_token %</span>}\n\n &lt;div class=<span>\"field\"</span>&gt;\n &lt;label for=<span>\"{{ form.title.id_for_label }}\"</span>&gt;Title&lt;/label&gt;\n {{ form.title }}\n {<span>% if</span> form.title.errors <span>%}</span>\n &lt;span class=<span>\"error\"</span>&gt;{{ form.title.errors<span>|first</span> }}&lt;/span&gt;\n {<span>% endif %</span>}\n &lt;/div&gt;\n\n &lt;div class=<span>\"field\"</span>&gt;\n &lt;label for=<span>\"{{ form.body.id_for_label }}\"</span>&gt;Body&lt;/label&gt;\n {{ form.body }}\n &lt;/div&gt;\n\n &lt;button type=<span>\"submit\"</span> class=<span>\"btn-primary\"</span>&gt;Save&lt;/button&gt;\n&lt;/form&gt;</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">Looping, less repetition</span>\n</div>\n<pre>&lt;form method=<span>\"post\"</span> class=<span>\"form\"</span>&gt;\n {<span>% csrf_token %</span>}\n {<span>% for</span> field <span>in</span> form <span>%}</span>\n &lt;div class=<span>\"field {% if field.errors %}field-error{% endif %}\"</span>&gt;\n {{ field.label_tag }}\n {{ field }}\n {<span>% if</span> field.help_text <span>%}</span>\n &lt;small&gt;{{ field.help_text }}&lt;/small&gt;\n {<span>% endif %</span>}\n {{ field.errors }}\n &lt;/div&gt;\n {<span>% endfor %</span>}\n &lt;button type=<span>\"submit\"</span>&gt;Save&lt;/button&gt;\n&lt;/form&gt;</pre>\n</div>\n<div class=\"step-body\">\n<p>To add your own CSS classes to inputs (for Tailwind or a design system), set widget attributes in the form class itself, not in the template:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n</div>\n<pre><span>class</span> <span>PostForm</span>(forms.ModelForm):\n <span>class</span> <span>Meta</span>:\n model = Post\n fields = [<span>\"title\"</span>, <span>\"body\"</span>]\n widgets = {\n <span>\"title\"</span>: forms.<span>TextInput</span>(attrs={<span>\"class\"</span>: <span>\"input\"</span>, <span>\"placeholder\"</span>: <span>\"Post title\"</span>}),\n <span>\"body\"</span>: forms.<span>Textarea</span>(attrs={<span>\"class\"</span>: <span>\"textarea\"</span>, <span>\"rows\"</span>: <span>6</span>}),\n }</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> <code>django-widget-tweaks</code> or <code>django-crispy-forms</code> let you add classes directly in the template instead of the form class, useful when designers iterate on markup without touching Python.</div>\n</section>\n<section class=\"step\" id=\"s17\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">17</div>\n<h2>Validation and error display</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Forms re-render with the user's submitted values and field-specific errors automatically. Replicating this by hand in vanilla JS/HTML is exactly the tedious work Django removes.</div>\n<div class=\"step-body\">\n<p>Custom validation lives on the form class as a <code>clean_&lt;fieldname&gt;</code> method for one field, or <code>clean()</code> for cross-field checks.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n</div>\n<pre><span>class</span> <span>SignupForm</span>(forms.Form):\n username = forms.<span>CharField</span>(max_length=<span>30</span>)\n password = forms.<span>CharField</span>(widget=forms.PasswordInput)\n password_confirm = forms.<span>CharField</span>(widget=forms.PasswordInput)\n\n <span>def</span> <span>clean_username</span>(self):\n username = self.cleaned_data[<span>\"username\"</span>]\n <span>if</span> User.objects.<span>filter</span>(username=username).<span>exists</span>():\n <span>raise</span> forms.<span>ValidationError</span>(<span>\"That username is taken.\"</span>)\n <span>return</span> username\n\n <span>def</span> <span>clean</span>(self):\n cleaned_data = <span>super</span>().<span>clean</span>()\n <span>if</span> cleaned_data.<span>get</span>(<span>\"password\"</span>) != cleaned_data.<span>get</span>(<span>\"password_confirm\"</span>):\n self.<span>add_error</span>(<span>\"password_confirm\"</span>, <span>\"Passwords do not match.\"</span>)\n <span>return</span> cleaned_data</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">Showing all errors at the top, plus per-field</span>\n</div>\n<pre>{<span>% if</span> form.non_field_errors <span>%}</span>\n &lt;div class=<span>\"alert alert-error\"</span>&gt;\n {<span>% for</span> error <span>in</span> form.non_field_errors <span>%}</span>\n &lt;p&gt;{{ error }}&lt;/p&gt;\n {<span>% endfor %</span>}\n &lt;/div&gt;\n{<span>% endif %</span>}\n\n&lt;form method=<span>\"post\"</span>&gt;\n {<span>% csrf_token %</span>}\n {<span>% for</span> field <span>in</span> form <span>%}</span>\n &lt;div class=<span>\"field\"</span>&gt;\n {{ field.label_tag }} {{ field }}\n {<span>% for</span> error <span>in</span> field.errors <span>%}</span>\n &lt;span class=<span>\"field-error\"</span>&gt;{{ error }}&lt;/span&gt;\n {<span>% endfor %</span>}\n &lt;/div&gt;\n {<span>% endfor %</span>}\n &lt;button type=<span>\"submit\"</span>&gt;Submit&lt;/button&gt;\n&lt;/form&gt;</pre>\n</div>\n<div>On a failed submission, the same template re-renders with the bound form. Field values the user already typed stay filled in automatically, and only the offending fields show errors, no manual state juggling required.</div>\n</section>\n<section class=\"step\" id=\"s18\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">18</div>\n<h2>File upload forms</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>File uploads need two things vanilla forms often skip: a different encoding type on the form tag, and request.FILES instead of request.POST in the view.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n</div>\n<pre><span>class</span> <span>PostForm</span>(forms.ModelForm):\n <span>class</span> <span>Meta</span>:\n model = Post\n fields = [<span>\"title\"</span>, <span>\"thumbnail\"</span>] <span># thumbnail is an ImageField on the model</span></pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n</div>\n<pre>&lt;form method=<span>\"post\"</span> enctype=<span>\"multipart/form-data\"</span>&gt;\n {<span>% csrf_token %</span>}\n {{ form.as_p }}\n &lt;button type=<span>\"submit\"</span>&gt;Upload&lt;/button&gt;\n&lt;/form&gt;</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n</div>\n<pre><span>def</span> <span>create_post</span>(request):\n <span>if</span> request.method == <span>\"POST\"</span>:\n form = <span>PostForm</span>(request.POST, request.FILES) <span># files come from a separate dict</span>\n <span>if</span> form.<span>is_valid</span>():\n form.<span>save</span>()\n <span>return</span> <span>redirect</span>(<span>\"post_list\"</span>)\n <span>else</span>:\n form = <span>PostForm</span>()\n <span>return</span> <span>render</span>(request, <span>\"blog/post_form.html\"</span>, {<span>\"form\"</span>: form})</pre>\n</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> forgetting <code>enctype=\"multipart/form-data\"</code> on the form tag. Without it, the browser submits files as plain text, the upload silently fails to actually transmit the file content.</div>\n</section>\n<section class=\"step\" id=\"s19\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-tip\">19</div>\n<h2>Formsets</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>This is Django's answer to dynamic repeating field groups, the \"add another item\" pattern you would otherwise hand-roll in JavaScript.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n</div>\n<pre><span>from</span> django.forms <span>import</span> modelformset_factory\n\nPhotoFormSet = <span>modelformset_factory</span>(Photo, fields=[<span>\"image\"</span>, <span>\"caption\"</span>], extra=<span>3</span>)\n\n<span>def</span> <span>gallery_upload</span>(request):\n formset = <span>PhotoFormSet</span>(request.POST <span>or</span> <span>None</span>, request.FILES <span>or</span> <span>None</span>, queryset=Photo.objects.<span>none</span>())\n <span>if</span> request.method == <span>\"POST\"</span> <span>and</span> formset.<span>is_valid</span>():\n formset.<span>save</span>()\n <span>return</span> <span>redirect</span>(<span>\"gallery\"</span>)\n <span>return</span> <span>render</span>(request, <span>\"gallery/upload.html\"</span>, {<span>\"formset\"</span>: formset})</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n</div>\n<pre>&lt;form method=<span>\"post\"</span> enctype=<span>\"multipart/form-data\"</span>&gt;\n {<span>% csrf_token %</span>}\n {{ formset.management_form }}\n {<span>% for</span> form <span>in</span> formset <span>%}</span>\n &lt;div class=<span>\"photo-row\"</span>&gt;{{ form.as_p }}&lt;/div&gt;\n {<span>% endfor %</span>}\n &lt;button type=<span>\"submit\"</span>&gt;Upload All&lt;/button&gt;\n&lt;/form&gt;</pre>\n</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> dropping <code>{{ formset.management_form }}</code>. It carries hidden fields tracking how many forms exist, without it Django cannot correctly process the submitted formset.</div>\n</section>\n<section class=\"step\" id=\"s20\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">20</div>\n<h2>Vanilla JS with Django data</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Your JavaScript skills transfer completely. The only new piece is how to safely hand Python data to a script tag.</div>\n<div class=\"step-body\">\n<p>Two safe ways to pass server-side data into client-side JS, avoiding both XSS issues and brittle string concatenation:</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">Option A: json_script (recommended)</span>\n</div>\n<pre>{{ posts<span>|json_script</span>:<span>\"posts-data\"</span> }}\n\n&lt;script&gt;\n <span>const</span> posts = JSON.<span>parse</span>(document.<span>getElementById</span>(<span>\"posts-data\"</span>).textContent);\n posts.<span>forEach</span>(p =&gt; console.<span>log</span>(p.title));\n&lt;/script&gt;</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">Option B: data attributes for small values</span>\n</div>\n<pre>&lt;div id=<span>\"post-card\"</span> data-post-id=<span>\"{{ post.id }}\"</span> data-slug=<span>\"{{ post.slug }}\"</span>&gt;\n ...\n&lt;/div&gt;\n\n&lt;script&gt;\n <span>const</span> card = document.<span>getElementById</span>(<span>\"post-card\"</span>);\n <span>const</span> postId = card.dataset.postId;\n&lt;/script&gt;</pre>\n</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> writing <code>const data = {{ posts }};</code> directly. Without <code>|json_script</code>, special characters in the data can break out of the script tag or produce invalid JS. <code>json_script</code> handles escaping safely.</div>\n<div>Static JS files behave like any vanilla project, loaded with <code>{% static %}</code> as shown in Step 9. The Django-specific part is only how data crosses from Python into that JS.</div>\n</section>\n<section class=\"step\" id=\"s21\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">21</div>\n<h2>Fetch and AJAX with CSRF</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>CSRF protection from Step 13 also applies to fetch and XHR requests. A plain fetch POST will fail with 403 until you attach the token manually.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">JavaScript</span>\n<span class=\"code-file\">static/js/main.js</span>\n</div>\n<pre><span>function</span> <span>getCookie</span>(name) {\n <span>const</span> match = document.cookie.<span>match</span>(<span>new</span> <span>RegExp</span>(<span>\"(^| )\"</span> + name + <span>\"=([^;]+)\"</span>));\n <span>return</span> match ? match[<span>2</span>] : <span>null</span>;\n}\n\n<span>async</span> <span>function</span> <span>likePost</span>(postId) {\n <span>const</span> response = <span>await</span> <span>fetch</span>(<span>`</span>/posts/<span>${postId}</span>/like/<span>`</span>, {\n method: <span>\"POST\"</span>,\n headers: {\n <span>\"X-CSRFToken\"</span>: <span>getCookie</span>(<span>\"csrftoken\"</span>),\n <span>\"Content-Type\"</span>: <span>\"application/json\"</span>,\n },\n });\n <span>const</span> data = <span>await</span> response.<span>json</span>();\n document.<span>getElementById</span>(<span>\"like-count\"</span>).textContent = data.likes;\n}</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">blog/views.py</span>\n</div>\n<pre><span>from</span> django.http <span>import</span> JsonResponse\n<span>from</span> django.views.decorators.http <span>import</span> require_POST\n\n<span>@require_POST</span>\n<span>def</span> <span>like_post</span>(request, post_id):\n post = <span>get_object_or_404</span>(Post, pk=post_id)\n post.likes += <span>1</span>\n post.<span>save</span>()\n <span>return</span> <span>JsonResponse</span>({<span>\"likes\"</span>: post.likes})</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> if <code>{% csrf_token %}</code> already renders elsewhere on the page, you can read it from the DOM instead of cookies: <code>document.querySelector('[name=csrfmiddlewaretoken]').value</code>.</div>\n</section>\n<section class=\"step\" id=\"s22\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">22</div>\n<h2>HTMX with Django</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>HTMX lets server-rendered Django templates behave like a single-page app, swapping HTML fragments without writing a JSON API or a frontend framework.</div>\n<div class=\"step-body\">\n<p>The idea: Django views can return small HTML fragments instead of full pages. HTMX attributes on any element trigger a request and swap the response straight into the DOM.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">Search box that updates results as you type</span>\n</div>\n<pre>&lt;script src=<span>\"https://unpkg.com/htmx.org@1.9.10\"</span>&gt;&lt;/script&gt;\n\n&lt;input type=<span>\"search\"</span> name=<span>\"q\"</span>\n hx-get=<span>\"{% url 'post_search' %}\"</span>\n hx-trigger=<span>\"keyup changed delay:300ms\"</span>\n hx-target=<span>\"#results\"</span>\n placeholder=<span>\"Search posts...\"</span>&gt;\n\n&lt;div id=<span>\"results\"</span>&gt;\n {<span>% include</span> <span>\"blog/_post_results.html\"</span> <span>%}</span>\n&lt;/div&gt;</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n</div>\n<pre><span>def</span> <span>post_search</span>(request):\n query = request.GET.<span>get</span>(<span>\"q\"</span>, <span>\"\"</span>)\n posts = Post.objects.<span>filter</span>(title__icontains=query) <span>if</span> query <span>else</span> Post.objects.<span>none</span>()\n <span>return</span> <span>render</span>(request, <span>\"blog/_post_results.html\"</span>, {<span>\"posts\"</span>: posts})</pre>\n</div>\n<div>The partial template <code>_post_results.html</code> contains only the inner markup (no <code>{% extends %}</code>), since HTMX swaps it directly into the page. A leading underscore is a common naming convention for fragments meant only for partial swaps.</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> HTMX sends the same cookies as a normal browser request, so <code>{% csrf_token %}</code> inside the triggering form still works. For non-form triggers like this search input, add HTMX's CSRF header globally once in your base template's script block.</div>\n</section>\n<section class=\"step\" id=\"s23\">\n<div class=\"step-header\">\n<div class=\"step-badge tone-info\">23</div>\n<h2>Messages framework (toasts/alerts)</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's messages framework replaces manually managing flash-message state across a redirect, a problem vanilla apps usually solve with session storage hacks.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings.py</span>\n</div>\n<pre>INSTALLED_APPS = [\n <span># ...</span>\n <span>\"django.contrib.messages\"</span>, <span># included by default in new projects</span>\n]\nMIDDLEWARE = [\n <span># ...</span>\n <span>\"django.contrib.sessions.middleware.SessionMiddleware\"</span>,\n <span>\"django.contrib.messages.middleware.MessageMiddleware\"</span>,\n]</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">blog/views.py</span>\n</div>\n<pre><span>from</span> django.contrib <span>import</span> messages\n\n<span>def</span> <span>create_post</span>(request):\n <span># ... after a successful save ...</span>\n messages.<span>success</span>(request, <span>\"Post published successfully.\"</span>)\n <span>return</span> <span>redirect</span>(<span>\"post_list\"</span>)</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">templates/partials/messages.html, included in base.html</span>\n</div>\n<pre>{<span>% if</span> messages <span>%}</span>\n &lt;div class=<span>\"toast-container\"</span>&gt;\n {<span>% for</span> message <span>in</span> messages <span>%}</span>\n &lt;div class=<span>\"toast toast-{{ message.tags }}\"</span>&gt;{{ message }}&lt;/div&gt;\n {<span>% endfor %</span>}\n &lt;/div&gt;\n{<span>% endif %</span>}</pre>\n</div>\n<div>Available levels are <code>messages.debug</code>, <code>.info</code>, <code>.success</code>, <code>.warning</code>, <code>.error</code>. Each becomes a CSS class via <code>message.tags</code> (e.g. <code>toast-success</code>), letting your CSS style each level distinctly. Messages survive exactly one redirect and then clear themselves automatically.</div>\n</section>\n<section class=\"step\" id=\"s24\">\n<div class=\"step-header\">\n<div class=\"step-badge\">24</div>\n<h2>Context processors</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>If every single view has to manually add the same variable to its context (like site settings or a cart count), that is a sign you need a context processor instead.</div>\n<div class=\"step-body\">\n<p>A context processor is a function that runs on every request and injects extra variables into every template's context automatically, no need to pass them from each view.</p>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/context_processors.py</span>\n</div>\n<pre><span>def</span> <span>site_settings</span>(request):\n <span>return</span> {\n <span>\"site_name\"</span>: <span>\"My Django Site\"</span>,\n <span>\"current_year\"</span>: <span>timezone</span>.<span>now</span>().year,\n }</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n<span class=\"code-file\">core/settings.py</span>\n</div>\n<pre>TEMPLATES = [\n {\n <span># ...</span>\n <span>\"OPTIONS\"</span>: {\n <span>\"context_processors\"</span>: [\n <span>\"django.template.context_processors.request\"</span>,\n <span>\"django.contrib.auth.context_processors.auth\"</span>,\n <span>\"django.contrib.messages.context_processors.messages\"</span>,\n <span>\"core.context_processors.site_settings\"</span>, <span># your custom one</span>\n ],\n },\n },\n]</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">now available in every template, no passing needed</span>\n</div>\n<pre>&lt;footer&gt;&amp;copy; {{ current_year }} {{ site_name }}&lt;/footer&gt;</pre>\n</div>\n<div class=\"tone-danger\"><strong>Common mistake:</strong> using context processors for page-specific data like a single post's comments. They run on every request, even ones that do not need that data, so reserve them strictly for truly global, lightweight values.</div>\n</section>\n<section class=\"step\" id=\"s25\">\n<div class=\"step-header\">\n<div class=\"step-badge\">25</div>\n<h2>Pagination UI</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Django's Paginator class handles slicing, but you still build the previous/next/page-number controls in the template yourself.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">Python</span>\n</div>\n<pre><span>from</span> django.core.paginator <span>import</span> Paginator\n\n<span>def</span> <span>post_list</span>(request):\n post_list = Post.objects.<span>all</span>().<span>order_by</span>(<span>\"-created\"</span>)\n paginator = <span>Paginator</span>(post_list, <span>10</span>) <span># 10 per page</span>\n page_number = request.GET.<span>get</span>(<span>\"page\"</span>)\n page_obj = paginator.<span>get_page</span>(page_number)\n <span>return</span> <span>render</span>(request, <span>\"blog/post_list.html\"</span>, {<span>\"page_obj\"</span>: page_obj})</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n</div>\n<pre>{<span>% for</span> post <span>in</span> page_obj <span>%}</span>\n &lt;article&gt;{{ post.title }}&lt;/article&gt;\n{<span>% endfor %</span>}\n\n&lt;nav class=<span>\"pagination\"</span>&gt;\n {<span>% if</span> page_obj.has_previous <span>%}</span>\n &lt;a href=<span>\"?page={{ page_obj.previous_page_number }}\"</span>&gt;Previous&lt;/a&gt;\n {<span>% endif %</span>}\n\n &lt;span&gt;Page {{ page_obj.number }} of {{ page_obj.paginator.num_pages }}&lt;/span&gt;\n\n {<span>% if</span> page_obj.has_next <span>%}</span>\n &lt;a href=<span>\"?page={{ page_obj.next_page_number }}\"</span>&gt;Next&lt;/a&gt;\n {<span>% endif %</span>}\n&lt;/nav&gt;</pre>\n</div>\n<div class=\"tone-tip\"><strong>Tip:</strong> <code>page_obj</code> is also iterable directly in the template (as shown above), you do not need a separate variable for the list of posts on the current page.</div>\n</section>\n<section class=\"step\" id=\"s26\">\n<div class=\"step-header\">\n<div class=\"step-badge\">26</div>\n<h2>SEO and meta blocks</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>Template inheritance from Step 5 makes per-page meta tags trivial once the base template is set up to support overrides.</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">base.html head section</span>\n</div>\n<pre>&lt;title&gt;{<span>% block</span> title <span>%}</span>My Site{<span>% endblock %</span>}&lt;/title&gt;\n&lt;meta name=<span>\"description\"</span> content=<span>\"{% block meta_description %}Default site description{% endblock %}\"</span>&gt;\n&lt;meta property=<span>\"og:title\"</span> content=<span>\"{% block og_title %}{{ self.title }}{% endblock %}\"</span>&gt;\n&lt;meta property=<span>\"og:image\"</span> content=<span>\"{% block og_image %}{% static 'images/og-default.png' %}{% endblock %}\"</span>&gt;\n&lt;link rel=<span>\"canonical\"</span> href=<span>\"{{ request.build_absolute_uri }}\"</span>&gt;</pre>\n</div>\n<div class=\"code-block\">\n<div class=\"code-header\">\n<span class=\"code-lang\">HTML</span>\n<span class=\"code-file\">blog/post_detail.html overrides per post</span>\n</div>\n<pre>{<span>% extends</span> <span>\"base.html\"</span> <span>%}</span>\n{<span>% block</span> title <span>%}</span>{{ post.title }} -- My Site{<span>% endblock %</span>}\n{<span>% block</span> meta_description <span>%}</span>{{ post.summary<span>|truncatechars</span>:<span>160</span> }}{<span>% endblock %</span>}\n{<span>% block</span> og_image <span>%}</span>{{ post.thumbnail.url }}{<span>% endblock %</span>}</pre>\n</div>\n<div>Each post now generates its own title, description, and social preview image, without duplicating the entire <code>&lt;head&gt;</code>. This is template inheritance doing real, practical work beyond just sharing a navbar.</div>\n</section>\n<section class=\"step\" id=\"s27\">\n<div class=\"step-header\">\n<div class=\"step-badge\">27</div>\n<h2>Common gotchas</h2>\n</div>\n<div class=\"step-why\"><strong>Why this step</strong>These are the mistakes that cost the most debugging time when moving from vanilla HTML to Django templates. Knowing them in advance saves hours.</div>\n<div class=\"step-body\">\n<p><strong>Template not found.</strong> Confirm <code>APP_DIRS: True</code> is set in <code>TEMPLATES</code> in settings.py, and that the template lives at <code>app_name/templates/app_name/file.html</code>, the nested folder matters for namespacing.</p>\n<p><strong>Static file 404 in development.</strong> Check <code>{% load static %}</code> is present, the path matches the folder structure exactly, and the dev server is actually running with <code>DEBUG = True</code>.</p>\n<p><strong>CSRF verification failed.</strong> The form is missing <code>{% csrf_token %}</code>, or a fetch request is missing the <code>X-CSRFToken</code> header as shown in Step 21.</p>\n<p><strong>Changes to CSS or templates not showing.</strong> Hard refresh the browser (Cmd/Ctrl+Shift+R), since static assets are often aggressively cached, especially after a CSS file rename.</p>\n<p><strong>Form re-submits and duplicates data on refresh.</strong> Always <code>redirect()</code> after a successful POST instead of rendering directly, this is the Post/Redirect/Get pattern and it prevents resubmission on browser refresh.</p>\n<p><strong>Variable shows nothing and no error.</strong> DTL silently renders missing or misspelled variables as an empty string instead of raising an error, unlike a JS console error. Double check spelling and that the variable was actually passed in the context dictionary.</p>\n<p><strong>{% if %} with a string \"False\".</strong> Template tags only understand actual Python booleans. A string like <code>\"False\"</code> passed from a query parameter is truthy because it is a non-empty string, convert it to a real boolean in the view first.</p>\n</div>\n<div class=\"tone-danger\"><strong>Debugging tip:</strong> install <code>django-debug-toolbar</code> in development. It shows exactly which template was used, the full context dictionary, every SQL query, and template render time, directly in the browser.</div>\n</section>\n<section id=\"cheatsheet\">\n<h2>Frontend Cheat Sheet</h2>\n<p class=\"section-sub\">Quick-reference template tags, filters, and form patterns.</p>\n<div class=\"cheat-grid\">\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Core Template Tags</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>{% extends \"base.html\" %}</code><span>Inherit from a parent template</span></div>\n<div class=\"cheat-item\"><code>{% block name %}...{% endblock %}</code><span>Define an overridable region</span></div>\n<div class=\"cheat-item\"><code>{% include \"partial.html\" %}</code><span>Insert a reusable template fragment</span></div>\n<div class=\"cheat-item\"><code>{% load static %}</code><span>Enable static and other app-specific tags</span></div>\n<div class=\"cheat-item\"><code>{% url 'name' arg %}</code><span>Reverse a named URL pattern</span></div>\n<div class=\"cheat-item\"><code>{% static 'path' %}</code><span>Resolve a static asset URL</span></div>\n<div class=\"cheat-item\"><code>{% csrf_token %}</code><span>Required inside every POST form</span></div>\n<div class=\"cheat-item\"><code>{{ block.super }}</code><span>Keep parent block content, then add more</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Loops and Conditionals</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>{% for x in list %}{% endfor %}</code><span>Loop over an iterable</span></div>\n<div class=\"cheat-item\"><code>{% empty %}</code><span>Fallback content for an empty loop</span></div>\n<div class=\"cheat-item\"><code>forloop.counter</code><span>1-indexed current position in a loop</span></div>\n<div class=\"cheat-item\"><code>forloop.first / .last</code><span>True on first or last iteration</span></div>\n<div class=\"cheat-item\"><code>{% if x %}{% elif y %}{% else %}</code><span>Conditional branching</span></div>\n<div class=\"cheat-item\"><code>{% if a and not b %}</code><span>and / or / not are supported keywords</span></div>\n<div class=\"cheat-item\"><code>{% with x=1 %}{% endwith %}</code><span>Create a local template variable</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Common Filters</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>{{ val|default:\"N/A\" }}</code><span>Fallback if value is falsy</span></div>\n<div class=\"cheat-item\"><code>{{ val|length }}</code><span>Length of a string or list</span></div>\n<div class=\"cheat-item\"><code>{{ val|truncatewords:30 }}</code><span>Cut off after 30 words</span></div>\n<div class=\"cheat-item\"><code>{{ val|date:\"F j, Y\" }}</code><span>Format a date or datetime</span></div>\n<div class=\"cheat-item\"><code>{{ val|linebreaks }}</code><span>Convert newlines into paragraphs</span></div>\n<div class=\"cheat-item\"><code>{{ val|safe }}</code><span>Disable auto-escaping (trusted content only)</span></div>\n<div class=\"cheat-item\"><code>{{ val|slugify }}</code><span>Convert text into a URL-safe slug</span></div>\n<div class=\"cheat-item\"><code>{{ val|join:\", \" }}</code><span>Join a list into a string</span></div>\n<div class=\"cheat-item\"><code>{{ list|json_script:\"id\" }}</code><span>Safely embed data for JS to read</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Form Rendering</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>{{ form.as_p }}</code><span>Quick render, each field wrapped in &lt;p&gt;</span></div>\n<div class=\"cheat-item\"><code>{{ form.as_div }}</code><span>Same, wrapped in &lt;div&gt; (Django 5+)</span></div>\n<div class=\"cheat-item\"><code>{{ field.label_tag }}</code><span>Render just the &lt;label&gt; for one field</span></div>\n<div class=\"cheat-item\"><code>{{ field.errors }}</code><span>Render errors for one specific field</span></div>\n<div class=\"cheat-item\"><code>form.non_field_errors</code><span>Errors not tied to a single field</span></div>\n<div class=\"cheat-item\"><code>field.id_for_label</code><span>Get the input's id, for a manual label</span></div>\n<div class=\"cheat-item\"><code>enctype=\"multipart/form-data\"</code><span>Required attribute for file upload forms</span></div>\n<div class=\"cheat-item\"><code>request.FILES</code><span>Where uploaded files arrive in the view</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>Static &amp; Media</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>STATIC_URL / STATICFILES_DIRS</code><span>Where static assets are served and sourced</span></div>\n<div class=\"cheat-item\"><code>MEDIA_URL / MEDIA_ROOT</code><span>Where uploaded user files live</span></div>\n<div class=\"cheat-item\"><code>app/static/app/...</code><span>Namespace static folders to avoid clashes</span></div>\n<div class=\"cheat-item\"><code>{{ obj.image.url }}</code><span>URL for an uploaded ImageField, no static tag</span></div>\n<div class=\"cheat-item\"><code>collectstatic</code><span>Gather all static files for production</span></div>\n<div class=\"cheat-item\"><code>django-tailwind</code><span>Tailwind build pipeline integrated with manage.py</span></div>\n</div>\n</div>\n<div class=\"cheat-card\">\n<div class=\"cheat-card-header\"><span></span><h3>JS Integration</h3></div>\n<div class=\"cheat-card-body\">\n<div class=\"cheat-item\"><code>{{ data|json_script:\"id\" }}</code><span>Safe way to pass Python data into JS</span></div>\n<div class=\"cheat-item\"><code>X-CSRFToken header</code><span>Required for fetch/AJAX POST requests</span></div>\n<div class=\"cheat-item\"><code>JsonResponse(dict)</code><span>Return JSON from a Django view</span></div>\n<div class=\"cheat-item\"><code>hx-get / hx-post</code><span>HTMX attributes for server-driven swaps</span></div>\n<div class=\"cheat-item\"><code>hx-target / hx-trigger</code><span>Where and when an HTMX request fires</span></div>\n<div class=\"cheat-item\"><code>messages.success(request, \"...\")</code><span>Flash message surfaced after a redirect</span></div>\n</div>\n</div>\n</div>\n</section>";

